class TestFetchFromApiResult:
    def test_success_returns_dict_with_status_200(self) -> None:
        class _R:
            def read(self):
                return b'{"five_hour": {"utilization": 1.0}}'

            def __enter__(self):
                return self

            def __exit__(self, *a):
                return False

        with patch(
            "claude_quota_exporter.fetcher.urllib.request.urlopen",
            return_value=_R(),
        ):
            result = fetch_from_api(token="tk", timeout_seconds=5)
        assert isinstance(result, FetchResult)
        assert result.status == 200
        assert result.payload == {"five_hour": {"utilization": 1.0}}

    def test_401_returns_status_401_none_payload(self) -> None:
        def _raise(req, timeout=None):
            raise urllib.error.HTTPError(
                getattr(req, "full_url", "u"),
                401,
                "Unauthorized",
                {},
                io.BytesIO(b""),
            )

        with patch(
            "claude_quota_exporter.fetcher.urllib.request.urlopen",
            side_effect=_raise,
        ):
            result = fetch_from_api(token="tk", timeout_seconds=5)
        assert result.status == 401
        assert result.payload is None

    def test_network_error_returns_status_zero(self) -> None:
        with patch(
            "claude_quota_exporter.fetcher.urllib.request.urlopen",
            side_effect=urllib.error.URLError("down"),
        ):
            result = fetch_from_api(token="tk", timeout_seconds=5)
        assert result.status == 0
        assert result.payload is None


