class TestReactive401Refresh:
    def test_fires_when_token_expired_and_no_recent_refresh(
        self, tmp_path: Path
    ) -> None:
        # Token expired 60s ago, no recent refresh; proactive will fire
        # first (also gated by skew), then fetch is OK with new token.
        f = _make_fetcher(tmp_path, expires_at=time.time() - 60)
        f._last_refresh_at = 0.0
        new_creds = Credentials(
            access_token="rotated-at",
            refresh_token="rotated-rt",
            expires_at=time.time() + 7200,
            issued_at=time.time(),
        )
        with (
            patch(
                "claude_quota_exporter.fetcher.auth.refresh",
                return_value=new_creds,
            ) as mock_refresh,
            patch(
                "claude_quota_exporter.fetcher.fetch_from_api",
                side_effect=[_ok()],
            ) as mock_fetch,
        ):
            assert f.refresh_if_due() is True
        # Proactive runs (expiry already in past), fetch succeeds on first try.
        assert mock_refresh.call_count == 1
        assert mock_fetch.call_count == 1
        assert f.refresh_success_count == 1

    def test_reactive_path_on_proactive_skipped_token(self, tmp_path: Path) -> None:
        # Token still appears fresh (expires in 7200s), so proactive doesn't
        # fire. But upstream returns 401 anyway. With token believed fresh,
        # reactive does NOT fire (gate: expiry within skew is False).
        f = _make_fetcher(tmp_path, expires_at=time.time() + 7200)
        with (
            patch(
                "claude_quota_exporter.fetcher.auth.refresh",
            ) as mock_refresh,
            patch(
                "claude_quota_exporter.fetcher.fetch_from_api",
                side_effect=[_fail(status=401)],
            ),
        ):
            assert f.refresh_if_due() is False
        mock_refresh.assert_not_called()
        assert f.failure_count == 1
        assert f.refresh_failure_count == 0

    def test_reactive_skipped_after_recent_proactive_refresh(
        self, tmp_path: Path
    ) -> None:
        # Realistic flow: proactive fires (token within skew), refresh
        # succeeds, fetch with the rotated token STILL returns 401 (rare
        # server-side case). Reactive must NOT fire because refresh would
        # not fix it — refreshed_recently gate triggers.
        f = _make_fetcher(tmp_path, expires_at=time.time() + 60)
        new_creds = Credentials(
            access_token="rotated",
            refresh_token="rt-new",
            expires_at=time.time() + 7200,
            issued_at=time.time(),
        )
        with (
            patch(
                "claude_quota_exporter.fetcher.auth.refresh",
                return_value=new_creds,
            ) as mock_refresh,
            patch(
                "claude_quota_exporter.fetcher.auth.write_back",
                return_value=True,
            ),
            patch(
                "claude_quota_exporter.fetcher.fetch_from_api",
                side_effect=[_fail(status=401)],
            ),
        ):
            assert f.refresh_if_due() is False
        # Exactly one refresh: proactive. Reactive did not fire because
        # we just rotated the token (refreshed_recently=True).
        assert mock_refresh.call_count == 1
        assert f.refresh_success_count == 1
        # The 401 still counts as a fetch failure.
        assert f.failure_count == 1


class TestWriteBackLatch:
    def test_mid_run_write_back_failure_latches_and_does_not_retry(
        self, tmp_path: Path
    ) -> None:
        f = _make_fetcher(tmp_path, expires_at=time.time() + 60)
        assert f.credentials_writable is True
        new_creds = Credentials(
            access_token="rotated-at",
            refresh_token="rotated-rt",
            expires_at=time.time() + 7200,
            issued_at=time.time(),
        )
        write_back_calls = {"count": 0}

        def _fake_write_back(*args, **kwargs):
            write_back_calls["count"] += 1
            return False

        with (
            patch(
                "claude_quota_exporter.fetcher.auth.refresh",
                return_value=new_creds,
            ),
            patch(
                "claude_quota_exporter.fetcher.auth.write_back",
                side_effect=_fake_write_back,
            ),
            patch(
                "claude_quota_exporter.fetcher.fetch_from_api",
                return_value=_ok(),
            ),
        ):
            f.refresh_if_due()
            assert f.credentials_writable is False
            # Force another refresh-eligible cycle.
            f._creds = Credentials(
                access_token="another",
                refresh_token="another-rt",
                expires_at=time.time() + 60,
                issued_at=time.time(),
            )
            f._last_success_at = 0.0
            f._last_refresh_at = 0.0
            f.refresh_if_due()
        assert write_back_calls["count"] == 1
